import zlib, base64, sys, os

# ✅ FIX: Add project root to sys.path to fix relative import issues
# This is critical for iOS/Termux/Android where relative imports fail
_project_root = os.path.dirname(os.path.abspath(__file__))
if _project_root not in sys.path:
    sys.path.insert(0, _project_root)

_PAYLOAD = ""

try:
    _src = zlib.decompress(base64.b64decode(_PAYLOAD)).decode("utf-8")
    exec(compile(_src, "<ftool>", "exec"), {
        "__name__": "__main__",
        "__file__": os.path.abspath(sys.argv[0])
    })
except Exception as _e:
    print(f"[ERROR] Khong the chay tool: {_e}")
    print(f"  Python: {sys.version}")
    print(f"  Platform: {sys.platform}")
    import traceback
    traceback.print_exc()
    sys.exit(1)
